func (this *LighterCore) ParseTransaction(transaction interface{}, optionalArgs ...interface{}) interface{} {
	//
	// fetchDeposits
	//     {
	//         "id": "2901843",
	//         "asset_id": 5,
	//         "amount": "100000.0",
	//         "timestamp": 1766112729741,
	//         "status": "completed",
	//         "l1_tx_hash": "0xa24d83d58e1fd72b2a44a12d1ec766fb061fa0b806de2fed940b5d8ecd50744d",
	//     }
	//
	// fetchWithdrawals
	//     {
	//         "id": "string",
	//         "amount": "0.1",
	//         "timestamp": "1640995200",
	//         "status": "failed",
	//         "type": "secure",
	//         "l1_tx_hash": "0x70997970C51812dc3A010C7d01b50e0d17dc79C8"
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var typeVar interface{} = this.SafeString(transaction, "type")
	if IsTrue(IsEqual(typeVar, nil)) {
		typeVar = "deposit"
	} else {
		typeVar = "withdrawal"
	}
	var timestamp interface{} = this.SafeInteger(transaction, "timestamp")
	var status interface{} = this.SafeString(transaction, "status")
	return map[string]interface{}{
		"info":        transaction,
		"id":          this.SafeString(transaction, "id"),
		"txid":        this.SafeString(transaction, "l1_tx_hash"),
		"type":        typeVar,
		"currency":    this.SafeCurrencyCode(this.SafeString(transaction, "asset_id"), currency),
		"network":     nil,
		"amount":      this.SafeNumber(transaction, "amount"),
		"status":      this.ParseTransactionStatus(status),
		"timestamp":   timestamp,
		"datetime":    this.Iso8601(timestamp),
		"address":     nil,
		"addressFrom": nil,
		"addressTo":   nil,
		"tag":         nil,
		"tagFrom":     nil,
		"tagTo":       nil,
		"updated":     nil,
		"comment":     nil,
		"fee":         nil,
		"internal":    nil,
	}
}
func (this *LighterCore) ParseTransactionStatus(status interface{}) interface{} {
	var statuses interface{} = map[string]interface{}{
		"failed":    "failed",
		"pending":   "pending",
		"completed": "ok",
		"claimable": "ok",
	}
	return this.SafeString(statuses, status, status)
}

