func (this *LighterCore) ParseTrade(trade interface{}, optionalArgs ...interface{}) interface{} {
	//
	//     {
	//         "trade_id": 17609,
	//         "tx_hash": "99ffeaa3899fbaa51043840ddf762fd18c182a33b5125092105bee57af11fab04edf5fd90e969abd",
	//         "type": "trade",
	//         "market_id": 0,
	//         "size": "10.2304",
	//         "price": "2958.75",
	//         "usd_amount": "30269.196000",
	//         "ask_id": 281474977339869,
	//         "bid_id": 562949952870533,
	//         "ask_client_id": 0,
	//         "bid_client_id": 0,
	//         "ask_account_id": 20,
	//         "bid_account_id": 1077,
	//         "is_maker_ask": true,
	//         "block_height": 102070,
	//         "timestamp": 1766386112741,
	//         "taker_position_size_before": "0.0000",
	//         "taker_entry_quote_before": "0.000000",
	//         "taker_position_sign_changed": true,
	//         "maker_position_size_before": "-1856.8547",
	//         "maker_entry_quote_before": "5491685.069325",
	//         "maker_initial_margin_fraction_before": 500
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId interface{} = this.SafeString(trade, "market_id")
	market = this.SafeMarket(marketId, market)
	var timestamp interface{} = this.SafeInteger(trade, "timestamp")
	var accountIndex interface{} = this.SafeString(trade, "account_index")
	var askAccountId interface{} = this.SafeString(trade, "ask_account_id")
	var bidAccountId interface{} = this.SafeString(trade, "bid_account_id")
	var isMakerAsk interface{} = this.SafeBool(trade, "is_maker_ask")
	var side interface{} = nil
	var orderId interface{} = nil
	if IsTrue(!IsEqual(accountIndex, nil)) {
		if IsTrue(IsEqual(accountIndex, askAccountId)) {
			side = "sell"
			orderId = this.SafeString(trade, "ask_id")
		} else if IsTrue(IsEqual(accountIndex, bidAccountId)) {
			side = "buy"
			orderId = this.SafeString(trade, "bid_id")
		}
	}
	var takerOrMaker interface{} = nil
	if IsTrue(IsTrue(!IsEqual(side, nil)) && IsTrue(!IsEqual(isMakerAsk, nil))) {
		var isMaker interface{} = Ternary(IsTrue((IsEqual(side, "sell"))), isMakerAsk, !IsTrue(isMakerAsk))
		takerOrMaker = Ternary(IsTrue(isMaker), "maker", "taker")
	}
	return this.SafeTrade(map[string]interface{}{
		"info":         trade,
		"id":           this.SafeString(trade, "trade_id"),
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       GetValue(market, "symbol"),
		"order":        orderId,
		"type":         this.SafeString(trade, "type"),
		"side":         side,
		"takerOrMaker": takerOrMaker,
		"price":        this.SafeString(trade, "price"),
		"amount":       this.SafeString(trade, "size"),
		"cost":         this.SafeString(trade, "usd_amount"),
		"fee":          nil,
	}, market)
}

